INSERT INTO manuscript (id, title, abstract_text, keywords, content, journal_name, author_id, author_name, status, submission_date, review_date, acceptance_date, publication_date, assigned_reviewer_id, assigned_reviewer_name) VALUES
(1, '基于深度学习的结构健康监测数据异常检测', '针对桥梁结构监测数据中的异常检测问题，提出一种基于CNN-LSTM混合模型的异常检测方法，在真实数据集上准确率达94.2%。', '["结构健康监测","深度学习","异常检测","CNN-LSTM"]', '1 引言\n结构健康监测系统产生的大量数据需要高效的异常检测方法。本文提出CNN-LSTM混合模型，利用CNN提取空间特征，LSTM捕获时序依赖。实验证明方法有效。', '工学版', 1, '张明辉', 'published', '2025-01-15', '2025-03-20', '2025-04-10', '2025-05-01', 1, '马文军'),
(2, '基于数字孪生的智能制造车间实时调度优化', '构建数字孪生驱动的车间调度框架，利用实时数据反馈实现动态优化，生产效率提升18.5%。', '["数字孪生","智能制造","车间调度","实时优化"]', '1 引言\n数字孪生为智能制造提供了新的范式。本文提出五维数字孪生模型，在真实制造车间验证了方法的有效性。', '工学版', 2, '李红霞', 'published', '2025-02-20', '2025-04-25', '2025-05-15', '2025-06-01', 2, '韩志强'),
(3, '碳纤维增强复合材料的冲击损伤容限研究', '研究碳纤维复合材料的低速冲击损伤演化规律，提出基于声发射的损伤评估方法。', '["碳纤维","复合材料","冲击损伤","声发射"]', '1 引言\n碳纤维复合材料对冲击敏感。本文通过落锤冲击实验和声发射监测，建立了损伤特征参数与剩余强度的关系模型。', '工学版', 3, '王建国', 'reviewing', '2025-11-10', NULL, NULL, NULL, 2, '韩志强'),
(4, '基于联邦学习的工业设备故障预测方法', '提出保护数据隐私的联邦学习框架用于设备故障预测，在多中心数据集上验证了有效性。', '["联邦学习","故障预测","工业物联网","隐私保护"]', '1 引言\n工业数据共享面临隐私保护挑战。本文提出联邦学习框架使多家工厂协作训练而不共享原始数据。', '工学版', 4, '陈思远', 'reviewing', '2025-12-05', NULL, NULL, NULL, 7, '潘伟'),
(5, '基于量子纠缠的量子密钥分发实验研究', '设计并实现了基于BB84协议的量子密钥分发系统，在50km光纤上实现了安全密钥率1.2kbps。', '["量子密钥分发","量子纠缠","BB84协议","量子通信"]', '1 引言\n量子密钥分发提供了信息理论安全的密钥交换方式。本文搭建了完整的QKD实验系统。', '理学版', 5, '刘洋', 'reviewing', '2025-10-15', NULL, NULL, NULL, 6, '孟祥宇'),
(6, '基于超导量子比特的量子纠错码实验研究', '在超导量子芯片上实现了表面码纠错方案，逻辑量子比特保真度达到99.1%。', '["量子计算","量子纠错","表面码","超导量子比特"]', '1 引言\n量子纠错是实现容错量子计算的关键。本文在超导量子处理器上实现了distance-3表面码。', '理学版', 6, '赵雪梅', 'reviewing', '2025-11-20', NULL, NULL, NULL, 6, '孟祥宇'),
(7, '增材制造钛合金的疲劳性能与寿命预测', '研究SLM成形Ti-6Al-4V合金的疲劳裂纹萌生机制，建立基于缺陷特征的疲劳寿命预测模型。', '["增材制造","钛合金","疲劳性能","寿命预测"]', '1 引言\n增材制造钛合金的疲劳性能受内部缺陷影响。本文通过X射线CT表征缺陷，建立了疲劳寿命与缺陷特征的定量关系。', '工学版', 1, '张明辉', 'reviewing', '2026-01-08', NULL, NULL, NULL, 3, '徐明达'),
(8, '基于机器学习的合金设计方法研究', '集成高通量计算和主动学习策略，加速高熵合金的成分优化，成功设计出具有优异力学性能的新型合金。', '["机器学习","合金设计","高熵合金","高通量计算"]', '1 引言\n机器学习为材料设计提供了新的工具。本文建立了高熵合金性能数据库，利用贝叶斯优化指导合金成分设计。', '工学版', 3, '王建国', 'published', '2025-04-10', '2025-06-15', '2025-07-01', '2025-08-01', 4, '崔海龙'),
(9, '面向6G通信的太赫兹超表面天线研究', '提出基于可重构超表面的太赫兹波束赋形天线，在0.1THz频段实现波束扫描范围±60°。', '["太赫兹","超表面","天线","6G通信"]', '1 引言\n太赫兹通信是6G关键技术之一。本文设计了基于PIN二极管的可重构超表面天线。', '工学版', 8, '孙丽华', 'reviewing', '2026-02-10', NULL, NULL, NULL, 1, '马文军'),
(10, '面向智能制造的工业机器人视觉引导系统', '设计基于深度学习的机器人视觉引导系统，实现复杂工件的精确抓取，成功率98.5%。', '["智能制造","工业机器人","视觉引导","深度学习"]', '1 引言\n机器人视觉引导是实现柔性制造的关键。本文提出6D姿态估计算法结合运动规划实现精确抓取。', '工学版', 2, '李红霞', 'accepted', '2025-09-18', '2025-11-22', '2025-12-10', NULL, 2, '韩志强'),
(11, '二维铁电材料的理论设计与物性研究', '基于第一性原理计算预测了新型二维铁电材料，揭示了其铁电性的微观起源，居里温度达420K。', '["二维材料","铁电性","第一性原理","居里温度"]', '1 引言\n二维铁电材料在非易失性存储器中有重要应用。本文通过高通量计算筛选了稳定的二维铁电候选材料。', '理学版', 6, '赵雪梅', 'published', '2025-02-15', '2025-04-20', '2025-05-10', '2025-06-01', 6, '孟祥宇'),
(12, '新型钙钛矿太阳能电池的界面工程研究', '通过界面修饰提升钙钛矿电池的稳定性和效率，光电转换效率达到25.8%，运行1000小时后保持92%效率。', '["钙钛矿太阳能电池","界面工程","稳定性","光电转换效率"]', '1 引言\n钙钛矿太阳能电池效率已超过25%，但稳定性仍是商业化的瓶颈。本文开发了新型界面钝化策略。', '理学版', 5, '刘洋', 'accepted', '2025-06-20', '2025-08-25', '2025-09-15', NULL, 6, '孟祥宇'),
(13, '数字人文视域下唐代诗歌知识图谱构建', '基于CBDB和全唐诗构建唐代诗人社会网络和诗歌意象知识图谱，包含5.2万实体和23万关系。', '["数字人文","知识图谱","唐代诗歌","社会网络"]', '1 引言\n数字人文方法为古典文学研究提供了新视角。本文构建了唐代诗歌的多维知识图谱。', '文科版', 9, '吴志强', 'published', '2025-03-05', '2025-05-10', '2025-06-01', '2025-07-01', 4, '崔海龙'),
(14, '数字经济对劳动力市场结构的影响研究', '基于2015-2024年省级面板数据，分析数字经济对就业结构和工资水平的影响，发现显著的结构转型效应。', '["数字经济","劳动力市场","就业结构","面板数据"]', '1 引言\n数字经济深刻改变了劳动力市场。本文利用DID和工具变量法识别了数字经济的就业效应。', '文科版', 10, '郑晓东', 'published', '2025-04-10', '2025-06-15', '2025-07-05', '2025-08-01', 5, '董建华'),
(15, '人工智能生成物的著作权保护路径研究', '比较分析中美欧AI著作权立法动态，提出基于"人类创造性贡献度"的差异化保护制度设计。', '["人工智能","著作权","生成物","法律保护"]', '1 引言\nAI生成内容对传统著作权制度提出了挑战。本文梳理了国际立法趋势并提出了我国的制度设计方案。', '文科版', 11, '黄文博', 'accepted', '2025-05-20', '2025-07-25', '2025-08-15', NULL, 5, '董建华'),
(16, '基于深度学习的眼底视网膜病变自动分级诊断', '提出基于EfficientNetV2和注意力机制的DR分级模型，在Kaggle数据集上AUC达0.978。', '["糖尿病视网膜病变","深度学习","自动诊断","医学图像"]', '1 引言\n糖尿病视网膜病变的早期筛查至关重要。本文提出基于深度学习的DR五级自动分级系统。', '生物医学版', 8, '孙丽华', 'published', '2025-05-10', '2025-07-15', '2025-08-05', '2025-09-01', 3, '徐明达'),
(17, '基于模型预测控制的四旋翼无人机轨迹跟踪', '提出基于非线性MPC的四旋翼轨迹跟踪控制器，在室外风扰条件下跟踪误差小于0.15m。', '["四旋翼","模型预测控制","轨迹跟踪","扰动抑制"]', '1 引言\n四旋翼无人机在复杂环境中需要鲁棒的控制器。本文设计了考虑风扰的非线性MPC控制器。', '工学版', 4, '陈思远', 'accepted', '2025-08-12', '2025-10-18', '2025-11-05', NULL, 1, '马文军'),
(18, '基于半监督学习的工业产品质量预测', '利用半监督自训练框架结合少量标注和大量未标注数据，在小样本场景下预测精度提升12.3%。', '["半监督学习","质量预测","小样本学习","智能制造"]', '1 引言\n工业场景中标注数据稀缺。本文提出结合伪标签生成和一致性正则化的半监督质量预测方法。', '工学版', 1, '张明辉', 'submitted', '2026-06-15', NULL, NULL, NULL, NULL, NULL),
(19, '面向边缘智能的神经网络模型压缩方法', '提出基于知识蒸馏和结构化剪枝的联合压缩框架，在保持精度98%的同时压缩比达20倍。', '["模型压缩","知识蒸馏","边缘智能","结构化剪枝"]', '1 引言\n边缘设备资源受限需要高效的模型压缩。本文提出联合优化剪枝和蒸馏的自适应压缩方案。', '工学版', 2, '李红霞', 'submitted', '2026-07-05', NULL, NULL, NULL, NULL, NULL),
(20, '形状记忆合金驱动器的非线性控制方法', '针对SMA驱动器的迟滞非线性，提出基于逆补偿和滑模控制的复合控制策略，跟踪精度提高至±0.5%。', '["形状记忆合金","迟滞非线性","滑模控制","智能材料"]', '1 引言\nSMA驱动器具有迟滞非线性。本文建立了Prandtl-Ishlinskii逆模型结合滑模控制实现精确跟踪。', '工学版', 3, '王建国', 'submitted', '2026-07-10', NULL, NULL, NULL, NULL, NULL),
(21, '基于拓扑绝缘体的自旋电子器件研究', '利用Bi2Te3拓扑绝缘体的自旋-动量锁定特性，设计了室温下高效自旋注入和检测器件。', '["拓扑绝缘体","自旋电子学","自旋注入","量子器件"]', '1 引言\n拓扑绝缘体的表面态为实现高效自旋操控提供了新途径。本文设计制备了Bi2Te3基自旋器件。', '理学版', 5, '刘洋', 'submitted', '2026-05-20', NULL, NULL, NULL, NULL, NULL),
(22, '基于表面增强拉曼散射的单分子检测技术', '制备了金纳米星SERS基底，实现了单分子水平的罗丹明6G检测，增强因子达4.2×10⁸。', '["表面增强拉曼","单分子检测","金纳米星","等离子体"]', '1 引言\nSERS技术可实现单分子级检测灵敏度。本文合成金纳米星并通过热点工程极大增强了拉曼信号。', '理学版', 6, '赵雪梅', 'submitted', '2026-06-01', NULL, NULL, NULL, NULL, NULL),
(23, '非线性偏微分方程的深度学习方法求解', '提出物理信息神经网络求解Navier-Stokes方程，相比传统数值方法在复杂几何上提速50倍。', '["物理信息神经网络","偏微分方程","深度学习","Navier-Stokes"]', '1 引言\nPINN将物理定律嵌入神经网络训练。本文提出改进的PINN框架求解不可压缩流体的Navier-Stokes方程。', '理学版', 7, '周伟', 'accepted', '2025-07-10', '2025-09-15', '2025-10-05', NULL, 6, '孟祥宇'),
(24, '基于强化学习的自适应交通信号控制', '提出多智能体深度强化学习方法协调多个路口信号控制，在仿真城市路网中平均行程时间减少22.4%。', '["交通信号控制","多智能体强化学习","智慧交通","协同控制"]', '1 引言\n城市交通拥堵需要智能信号控制。本文采用QMIX算法实现多路口协同信号优化。', '工学版', 8, '孙丽华', 'published', '2025-03-10', '2025-05-15', '2025-06-01', '2025-07-01', 4, '崔海龙'),
(25, '社交媒体舆情传播的动力学建模与干预策略', '构建考虑信息异质性的舆情传播SIR-H模型，提出基于关键节点识别的干预策略。', '["舆情传播","动力学模型","干预策略","社交网络"]', '1 引言\n社交媒体加速了舆情传播。本文在传统SIR模型基础上引入信息异质性和用户理性度因素。', '文科版', 9, '吴志强', 'reviewing', '2026-02-28', NULL, NULL, NULL, 5, '董建华'),
(26, 'ESG信息披露对企业融资约束的影响研究', '基于2018-2024年A股上市公司数据，发现ESG信息披露质量与企业融资约束呈显著负相关。', '["ESG","信息披露","融资约束","企业社会责任"]', '1 引言\nESG投资理念在中国快速发展。本文构建了ESG披露质量评价指标体系。', '文科版', 10, '郑晓东', 'reviewing', '2026-03-15', NULL, NULL, NULL, 5, '董建华'),
(27, '唐宋变革期江南水利治理的比较研究', '比较唐宋两代太湖流域水利治理模式的差异，揭示国家权力与地方社会互动的演变轨迹。', '["唐宋变革","水利治理","江南","国家与社会"]', '1 引言\n水利治理是观察古代国家-社会关系的重要窗口。本文细致比较了唐宋太湖流域的水利管理模式。', '文科版', 11, '黄文博', 'submitted', '2026-04-10', NULL, NULL, NULL, NULL, NULL),
(28, '基于语料库的现代汉语新词语生成机制研究', '基于国家语委语料库2015-2024年新词语，归纳了类推、缩略、谐音等六种主要生成机制。', '["新词语","生成机制","语料库语言学","现代汉语"]', '1 引言\n新词语是社会发展的语言镜像。本文基于大规模语料库运用定量和定性相结合的方法分析新词语。', '文科版', 12, '林嘉怡', 'submitted', '2026-06-12', NULL, NULL, NULL, NULL, NULL),
(29, 'CAR-T细胞治疗实体瘤的临床前研究', '靶向CLDN18.2的CAR-T细胞在胃癌PDX模型中展示出强效抗肿瘤活性，肿瘤完全消退率达60%。', '["CAR-T","实体瘤","CLDN18.2","免疫治疗"]', '1 引言\nCAR-T在血液瘤中取得了成功但在实体瘤中面临挑战。本文开发了新一代CAR-T克服肿瘤微环境抑制。', '生物医学版', 13, '杨建华', 'published', '2025-04-22', '2025-06-28', '2025-07-20', '2025-08-15', 3, '徐明达'),
(30, '基于单细胞转录组的肿瘤异质性分析', '对15例肝癌样本进行scRNA-seq分析，鉴定出3种具有不同药物敏感性的肿瘤干细胞亚群。', '["单细胞转录组","肿瘤异质性","肝癌","肿瘤干细胞"]', '1 引言\n肿瘤异质性是治疗失败的重要原因。本文通过单细胞测序揭示了肝癌的细胞多样性图谱。', '生物医学版', 14, '何晓峰', 'published', '2025-05-15', '2025-07-20', '2025-08-10', '2025-09-01', 3, '徐明达'),
(31, '基于多物理场耦合的锂电池热失控模拟', '建立电化学-热-力学多场耦合模型预测锂电池热失控行为，实验验证误差小于8%。', '["锂电池","热失控","多物理场耦合","数值模拟"]', '1 引言\n锂电池热失控是电动汽车安全的核心问题。本文建立了多物理场耦合模型模拟热失控过程。', '理学版', 7, '周伟', 'reviewing', '2026-01-05', NULL, NULL, NULL, 2, '韩志强'),
(32, '基于深度强化学习的机器人灵巧操作', '提出结合触觉感知的深度强化学习框架，实现机器人在未知物体上的灵巧抓取和操作。', '["深度强化学习","灵巧操作","触觉感知","机器人"]', '1 引言\n机器人灵巧操作是AI领域的重大挑战。本文在仿真和真实机器人平台上验证了方法的有效性。', '工学版', 1, '张明辉', 'submitted', '2026-06-30', NULL, NULL, NULL, NULL, NULL),
(33, '互联网平台经济中的劳动权益保障研究', '分析平台用工的劳动法律适用困境，提出基于经济从属性的"三分法"保护框架。', '["平台经济","劳动权益","从属性","社会保障"]', '1 引言\n平台经济催生了大量新型用工关系。本文考察了国内外平台用工的立法趋势。', '文科版', 9, '吴志强', 'rejected', '2026-01-10', '2026-03-05', NULL, NULL, 5, '董建华'),
(34, '远程办公对员工工作投入的影响机制研究', '基于JD-R模型，调查1024名远程办公者，发现工作自主性和社会支持是正向影响的关键因素。', '["远程办公","工作投入","JD-R模型","工作自主性"]', '1 引言\n远程办公已成为普遍的工作模式。本文采用问卷调查和结构方程模型分析影响机制。', '文科版', 10, '郑晓东', 'submitted', '2026-06-25', NULL, NULL, NULL, NULL, NULL),
(35, '晚清报刊中科学话语的传播与接受研究', '以《格致汇编》《万国公报》为语料，考察晚清科学知识传播的话语策略和社会接受度。', '["晚清报刊","科学话语","知识传播","文化接受"]', '1 引言\n晚清时期报刊是科学知识传播的主要媒介。本文运用话语分析法揭示了科学的本土化过程。', '文科版', 12, '林嘉怡', 'submitted', '2026-05-28', NULL, NULL, NULL, NULL, NULL),
(36, '基于CRISPR-Cas12a的病原体快速检测方法', '开发基于CRISPR-Cas12a和RPA等温扩增的SARS-CoV-2检测方法，灵敏度达10拷贝/μL。', '["CRISPR-Cas12a","病原体检测","等温扩增","即时检测"]', '1 引言\n快速准确的病原体检测对疫情防控至关重要。本文整合RPA和CRISPR技术实现了POCT检测。', '生物医学版', 13, '杨建华', 'reviewing', '2026-04-15', NULL, NULL, NULL, 3, '徐明达'),
(37, '基于外泌体的肿瘤液体活检技术研究', '开发基于免疫磁珠的外泌体捕获微流控芯片，在50例肺癌患者血浆中检出率85%。', '["外泌体","液体活检","微流控","肿瘤标志物"]', '1 引言\n外泌体作为液体活检标志物具有独特优势。本文设计了集外泌体捕获和检测于一体的微流控平台。', '生物医学版', 14, '何晓峰', 'reviewing', '2026-05-10', NULL, NULL, NULL, 3, '徐明达'),
(38, '中药复方网络药理学分析平台的开发', '构建包含238味常用中药和9.8万个化学成分的中药复方网络药理学分析平台。', '["网络药理学","中药复方","靶点预测","数据库"]', '1 引言\n网络药理学为中药复方的机制研究提供了新方法。本文整合多组学数据构建了分析平台。', '生物医学版', 15, '唐丽娟', 'submitted', '2026-07-02', NULL, NULL, NULL, NULL, NULL),
(39, '基于类器官模型的药物肝毒性评估', '建立人源肝脏类器官的高通量药物毒性评估平台，对120种药物进行了肝毒性分级。', '["肝脏类器官","药物毒性","高通量筛选","3D培养"]', '1 引言\n药物肝毒性是药物研发失败的主要原因之一。本文建立了肝脏类器官标准化培养和毒性评价体系。', '生物医学版', 13, '杨建华', 'accepted', '2025-09-15', '2025-11-20', '2025-12-10', NULL, 3, '徐明达'),
(40, 'mRNA疫苗递送载体的优化设计', '设计可电离脂质纳米颗粒递送mRNA疫苗，小鼠模型中和抗体滴度较对照组高3.2倍。', '["mRNA疫苗","脂质纳米颗粒","递送载体","免疫应答"]', '1 引言\nmRNA疫苗的成功离不开高效递送载体。本文通过组合化学方法优化LNPs的脂质组成。', '生物医学版', 14, '何晓峰', 'submitted', '2026-07-08', NULL, NULL, NULL, NULL, NULL);
