INSERT INTO review_record (id, paper_id, paper_title, reviewer_id, reviewer_name, decision, comments, review_date) VALUES
(1, 1, '基于深度学习的结构健康监测数据异常检测', 1, '马文军', 'approved', '方法设计合理，CNN-LSTM混合模型在桥梁监测数据上表现优异。实验设计充分，建议补充与其他SOTA方法的对比。', '2025-03-20'),
(2, 2, '基于数字孪生的智能制造车间实时调度优化', 2, '韩志强', 'approved', '数字孪生与车间调度结合的思路新颖，实际应用效果显著。论文结构清晰数据翔实，同意发表。', '2025-04-25'),
(3, 29, 'CAR-T细胞治疗实体瘤的临床前研究', 3, '徐明达', 'approved', 'CAR-T靶向CLDN18.2治疗胃癌的研究具有重要的临床转化价值。动物实验数据可靠，建议补充CAR-T持久性数据。', '2025-06-28'),
(4, 8, '基于机器学习的合金设计方法研究', 4, '崔海龙', 'approved', '高通量计算与主动学习相结合的方法具有很好的创新性，成功设计新型高熵合金验证了方法的有效性。', '2025-06-15'),
(5, 14, '数字经济对劳动力市场结构的影响研究', 5, '董建华', 'approved', '实证分析严谨，工具变量选择合理。数字经济对就业结构的结构性影响分析深入，具有政策参考价值。', '2025-06-15'),
(6, 11, '二维铁电材料的理论设计与物性研究', 6, '孟祥宇', 'approved', '第一性原理计算系统的材料筛选方法规范，预测的铁电材料居里温度高于室温具有应用前景。', '2025-04-20'),
(7, 17, '基于模型预测控制的四旋翼无人机轨迹跟踪', 1, '马文军', 'approved', '非线性MPC控制器设计合理，室外实验验证充分。建议进一步讨论计算复杂度和实时性。', '2025-10-18'),
(8, 10, '面向智能制造的工业机器人视觉引导系统', 2, '韩志强', 'approved', '视觉引导系统的设计完整，6D姿态估计算法精度高。98.5%的抓取成功率证明了系统的可靠性。', '2025-11-22'),
(9, 30, '基于单细胞转录组的肿瘤异质性分析', 3, '徐明达', 'approved', '单细胞测序数据分析方法先进，鉴定出的肿瘤干细胞亚群具有临床意义。建议增加空间转录组验证。', '2025-07-20'),
(10, 24, '基于强化学习的自适应交通信号控制', 4, '崔海龙', 'approved', '多智能体RL方法在交通信号控制中的应用具有很好的实践价值。仿真实验规模大，结果有说服力。', '2025-05-15'),
(11, 15, '人工智能生成物的著作权保护路径研究', 5, '董建华', 'approved', '对国际AI著作权立法趋势的梳理全面，提出的"人类创造性贡献度"标准具有理论创新性和实践可操作性。', '2025-07-25'),
(12, 23, '非线性偏微分方程的深度学习方法求解', 6, '孟祥宇', 'approved', 'PINN框架的改进具有理论创新性，在Navier-Stokes方程求解上的加速效果显著。建议讨论适用范围和局限性。', '2025-09-15'),
(13, 7, '增材制造钛合金的疲劳性能与寿命预测', 1, '马文军', 'rejected', '研究内容具有一定的工程价值，但存在以下不足：样本量偏小（仅12个试样），统计分析不够充分；仅关注了SLM工艺，未与其他增材制造工艺对比。建议补充实验后重新投稿。', '2026-02-20'),
(14, 3, '碳纤维增强复合材料的冲击损伤容限研究', 2, '韩志强', 'rejected', '声发射方法用于复合材料损伤监测已有较多研究，论文在方法上缺乏足够的创新性。建议结合新的传感技术或数据分析方法。', '2026-01-05'),
(15, 36, '基于CRISPR-Cas12a的病原体快速检测方法', 3, '徐明达', 'rejected', 'CRISPR-Dx领域发展迅速，本文的方法与已报道的方法相比优势不够突出。建议在多重检测或定量能力方面做更多创新。', '2026-05-20'),
(16, 9, '面向6G通信的太赫兹超表面天线研究', 4, '崔海龙', 'rejected', '超表面天线的设计方法较为常规，可重构机制缺乏详细的物理分析。建议补充材料特性的表征和更详细的电磁仿真。', '2026-03-25'),
(17, 25, '社交媒体舆情传播的动力学建模与干预策略', 5, '董建华', 'rejected', '舆情传播模型已有较多研究成果，SIR-H模型的改进幅度有限。建议选择具体的舆情案例进行实证验证，增强模型的说服力。', '2026-04-10'),
(18, 5, '基于量子纠缠的量子密钥分发实验研究', 6, '孟祥宇', 'rejected', 'BB84协议QKD系统的实现较为成熟，论文在实验技术上的创新不够显著。建议在系统集成度或安全性分析方面做出特色。', '2026-01-05'),
(19, 16, '基于深度学习的眼底视网膜病变自动分级诊断', 1, '马文军', 'approved', 'EfficientNetV2结合注意力机制的方法设计合理，AUC 0.978达到了临床可用水平。建议在不同种族数据集上验证泛化性。', '2025-07-15'),
(20, 8, '基于机器学习的合金设计方法研究', 2, '韩志强', 'approved', '审稿人一致认为论文具有很好的创新价值。方法学框架完整，实验结果验证了方法的有效性，达到了发表水平。', '2025-06-20'),
(21, 24, '基于强化学习的自适应交通信号控制', 6, '孟祥宇', 'approved', 'QMIX算法在多路口协同控制中的效果显著，消融实验展示了各模块的贡献。建议讨论部署到实际交通系统的可行性。', '2025-05-20'),
(22, 39, '基于类器官模型的药物肝毒性评估', 3, '徐明达', 'approved', '建立了标准化的肝脏类器官培养和毒性评价体系，120种药物的筛选规模较大。建议补充与动物实验的对比数据。', '2025-11-20'),
(23, 13, '数字人文视域下唐代诗歌知识图谱构建', 4, '崔海龙', 'approved', '知识图谱的构建方法规范，数据规模可观。唐代诗人社会网络分析具有一定的学术创新价值。', '2025-05-10'),
(24, 12, '新型钙钛矿太阳能电池的界面工程研究', 6, '孟祥宇', 'approved', '界面钝化策略新颖，25.8%的效率和优异的稳定性令人印象深刻。建议补充大面积器件的性能数据。', '2025-08-25'),
(25, 18, '基于半监督学习的工业产品质量预测', 1, '马文军', 'rejected', '小样本场景下的半监督学习方法有一定价值，但实验对比的基线方法太少，难以说明方法的优势。建议补充更多对比实验。', '2026-06-30'),
(26, 6, '基于超导量子比特的量子纠错码实验研究', 6, '孟祥宇', 'rejected', '表面码纠错方案是当前研究热点，但本文的实验规模较小（仅distance-3），逻辑错误率距离break-even尚有差距。', '2026-01-10'),
(27, 31, '基于多物理场耦合的锂电池热失控模拟', 2, '韩志强', 'approved', '多物理场耦合模型的设计合理，热失控过程的模拟精度较高。建议补充不同电池类型的适用性讨论。', '2026-02-15'),
(28, 37, '基于外泌体的肿瘤液体活检技术研究', 3, '徐明达', 'approved', '微流控芯片设计精巧，在不增加设备复杂度的前提下提高了外泌体捕获效率。85%的检出率具有临床潜力。', '2026-06-01'),
(29, 4, '基于联邦学习的工业设备故障预测方法', 4, '崔海龙', 'approved', '联邦学习应用于工业设备故障预测具有前瞻性。多中心数据验证充分证明了方法的数据隐私保护和协同学习优势。', '2026-01-15'),
(30, 26, 'ESG信息披露对企业融资约束的影响研究', 5, '董建华', 'approved', '实证设计合理，ESG披露质量指标体系的构建方法规范。结论对政策制定和企业实践具有参考价值。', '2026-04-20');
